gen_ternary_complex_expr: Generate ARM64 code for a ternary (?:) expression, delegating sub‑expression handling to gen_ternary_subexpr.

19    int gen_ternary_complex_expr(std::shared_ptr<ASTNode> ternary_node,
20                                 std::shared_ptr<SymbolTable> symbol_table,
21                                 std::shared_ptr<CodeGenContext> codegen_ctx,
22                                 std::string& assembly_output,
23                                 std::vector<std::string>& error_list,
24                                 EReg dest_reg)
25    {
26        PRINT_TEST("gen_ternary_complex_expr: start");
27    
28        /* --------------------------------------------------------------------
29           Argument validation
30           -------------------------------------------------------------------- */
31        if (!ternary_node) {
32            error_list.push_back("gen_ternary_complex_expr: null node");
33            PRINT_TEST("%s", error_list.back().c_str());
34            return 1;
35        }
36        if (!symbol_table) {
37            error_list.push_back("gen_ternary_complex_expr: null symbol table");
38            PRINT_TEST("%s", error_list.back().c_str());
39            return 1;
40        }
41        if (!codegen_ctx) {
42            error_list.push_back("gen_ternary_complex_expr: null codegen context");
43            PRINT_TEST("%s", error_list.back().c_str());
44            return 1;
45        }
46        if (ternary_node->children.size() != 3) {
47            error_list.push_back("gen_ternary_complex_expr: malformed ternary expression");
48            PRINT_TEST("%s", error_list.back().c_str());
49            return 1;
50        }
51        if (dest_reg == EReg::SP) {
52            error_list.push_back("gen_ternary_complex_expr: destination register exhausted");
53            PRINT_TEST("%s", error_list.back().c_str());
54            return 1;
55        }
56    
57        /* --------------------------------------------------------------------
58           Generate unique labels for the three blocks and the end.
59           -------------------------------------------------------------------- */
60        std::string base_label = "ternary_" + codegen_ctx->label_counter;
61        std::string true_label  = base_label + "_true";
62        std::string false_label = base_label + "_false";
63        std::string end_label   = base_label + "_end";
64    
65        /* Increment the numeric label counter (assumed decimal string). */
66        unsigned long cnt = 0;
67        for (char c : codegen_ctx->label_counter) {
68            if (c >= '0' && c <= '9')
69                cnt = cnt * 10 + static_cast<unsigned long>(c - '0');
70            else {
71                error_list.push_back("gen_ternary_complex_expr: invalid label counter");
72                PRINT_TEST("%s", error_list.back().c_str());
73                return 1;
74            }
75        }
76        ++cnt;
77        codegen_ctx->label_counter = std::to_string(cnt);
78    
79        int status = 0;
80        EReg sub_reg = EReg::SP;               // will hold the result of each sub‑expression
81    
82        /* --------------------------------------------------------------------
83           1) Evaluate the condition expression.
84           -------------------------------------------------------------------- */
85        status = gen_ternary_subexpr(ternary_node->children[0],
86                                     symbol_table,
87                                     codegen_ctx,
88                                     assembly_output,
89                                     error_list,
90                                     sub_reg);
91        if (status != 0) {
92            error_list.push_back("gen_ternary_complex_expr: condition evaluation failed");
93            PRINT_TEST("%s", error_list.back().c_str());
94            return status;
95        }
96    
97        /* Emit compare and branch to false label if condition == 0 */
98        {
99            std::string cond_reg_name = "x" + std::to_string(static_cast<std::uint32_t>(sub_reg));
100           assembly_output += "cmp " + cond_reg_name + ", #0\n";
101           assembly_output += "b.eq " + false_label + "\n";
102       }
103       /* Condition register is no longer needed – release it. */
104       release_reg(codegen_ctx, sub_reg);
105   
106       /* --------------------------------------------------------------------
107          2) True branch
108          -------------------------------------------------------------------- */
109       assembly_output += true_label + ":\n";
110       status = gen_ternary_subexpr(ternary_node->children[1],
111                                    symbol_table,
112                                    codegen_ctx,
113                                    assembly_output,
114                                    error_list,
115                                    sub_reg);
116       if (status != 0) {
117           error_list.push_back("gen_ternary_complex_expr: true branch evaluation failed");
118           PRINT_TEST("%s", error_list.back().c_str());
119           return status;
120       }
121   
122       {
123           std::string true_reg_name = "x" + std::to_string(static_cast<std::uint32_t>(sub_reg));
124           std::string dest_reg_name = "x" + std::to_string(static_cast<std::uint32_t>(dest_reg));
125           assembly_output += "mov " + dest_reg_name + ", " + true_reg_name + "\n";
126           assembly_output += "b " + end_label + "\n";
127       }
128       if (sub_reg != dest_reg)
129           release_reg(codegen_ctx, sub_reg);
130   
131       /* --------------------------------------------------------------------
132          3) False branch
133          -------------------------------------------------------------------- */
134       assembly_output += false_label + ":\n";
135       status = gen_ternary_subexpr(ternary_node->children[2],
136                                    symbol_table,
137                                    codegen_ctx,
138                                    assembly_output,
139                                    error_list,
140                                    sub_reg);
141       if (status != 0) {
142           error_list.push_back("gen_ternary_complex_expr: false branch evaluation failed");
143           PRINT_TEST("%s", error_list.back().c_str());
144           return status;
145       }
146   
147       {
148           std::string false_reg_name = "x" + std::to_string(static_cast<std::uint32_t>(sub_reg));
149           std::string dest_reg_name  = "x" + std::to_string(static_cast<std::uint32_t>(dest_reg));
150           assembly_output += "mov " + dest_reg_name + ", " + false_reg_name + "\n";
151       }
152       if (sub_reg != dest_reg)
153           release_reg(codegen_ctx, sub_reg);
154   
155       /* --------------------------------------------------------------------
156          4) End label
157          -------------------------------------------------------------------- */
158       assembly_output += end_label + ":\n";
159   
160       PRINT_TEST("gen_ternary_complex_expr: success");
161       return 0;
162   }


