Providing requested information for the function 'gen_ternary_subexpr':

gen_ternary_subexpr: Generates code for a ternary sub‑expression, captures its result register and releases temporaries.

17    int gen_ternary_subexpr(std::shared_ptr<ASTNode> expr_node,
18                            std::shared_ptr<SymbolTable> symbol_table,
19                            std::shared_ptr<CodeGenContext> codegen_ctx,
20                            std::string& assembly_output,
21                            std::vector<std::string>& error_list,
22                            EReg& result_reg)
23    {
24        PRINT_TEST("gen_ternary_subexpr: start");
25    
26        /* --------------------------------------------------------------------
27           Argument validation
28           -------------------------------------------------------------------- */
29        if (!expr_node) {
30            error_list.push_back("gen_ternary_subexpr: null expression node");
31            PRINT_TEST("%s", error_list.back().c_str());
32            return 1;
33        }
34        if (!symbol_table) {
35            error_list.push_back("gen_ternary_subexpr: null symbol table");
36            PRINT_TEST("%s", error_list.back().c_str());
37            return 1;
38        }
39        if (!codegen_ctx) {
40            error_list.push_back("gen_ternary_subexpr: null codegen context");
41            PRINT_TEST("%s", error_list.back().c_str());
42            return 1;
43        }
44    
45        /* --------------------------------------------------------------------
46           Snapshot of registers that were already allocated before this call.
47           -------------------------------------------------------------------- */
48        std::set<EReg> pre_regs_set;
49        for (const std::pair<const std::string, EReg> kv : codegen_ctx->register_allocation) {
50            pre_regs_set.insert(kv.second);
51        }
52    
53        /* --------------------------------------------------------------------
54           Generate code for the sub‑expression.
55           -------------------------------------------------------------------- */
56        int status = gen_expr(expr_node,
57                              symbol_table,
58                              codegen_ctx,
59                              assembly_output,
60                              error_list);
61        if (status != 0) {
62            error_list.push_back("gen_ternary_subexpr: sub‑expression generation failed");
63            PRINT_TEST("%s", error_list.back().c_str());
64            return status;
65        }
66    
67        /* --------------------------------------------------------------------
68           Retrieve the register that holds the sub‑expression result.
69           -------------------------------------------------------------------- */
70        std::map<std::string, EReg>::iterator last_expr_it =
71            codegen_ctx->register_allocation.find("__last_expr__");
72        if (last_expr_it == codegen_ctx->register_allocation.end()) {
73            error_list.push_back("gen_ternary_subexpr: missing result register");
74            PRINT_TEST("%s", error_list.back().c_str());
75            return 1;
76        }
77        result_reg = last_expr_it->second;
78    
79        /* --------------------------------------------------------------------
80           Release any temporary registers allocated during the sub‑expression
81           that are not the final result register.
82           -------------------------------------------------------------------- */
83        std::vector<std::string> keys_to_release;
84        for (const std::pair<const std::string, EReg> kv : codegen_ctx->register_allocation) {
85            const std::string& key = kv.first;
86            EReg reg = kv.second;
87    
88            if (key == "__last_expr__" || reg == result_reg) {
89                continue;
90            }
91    
92            if (pre_regs_set.find(reg) == pre_regs_set.end()) {
93                keys_to_release.push_back(key);
94            }
95        }
96    
97        for (const std::string& key : keys_to_release) {
98            std::map<std::string, EReg>::iterator it =
99                codegen_ctx->register_allocation.find(key);
100           if (it != codegen_ctx->register_allocation.end()) {
101               release_reg(codegen_ctx, it->second);
102           }
103       }
104   
105       PRINT_TEST("gen_ternary_subexpr: success, result_reg=%u",
106                  static_cast<std::uint32_t>(result_reg));
107       return 0;
108   }


