map_node_to_asm: Dispatches an AST node to the appropriate assembly emitter after basic validation.

17    void map_node_to_asm(std::shared_ptr<ASTNode> node,
18                         std::shared_ptr<CodeGenResult> codegen_result,
19                         bool verbose,
20                         std::vector<bool>& temp_regs,
21                         unsigned int& label_counter)
22    {
23        // Argument validation
24        if (!node) {
25            PRINT_TEST("map_node_to_asm: received null node");
26            return;
27        }
28    
29        if (!codegen_result) {
30            PRINT_TEST("map_node_to_asm: received null codegen_result");
31            return;
32        }
33    
34        // Abort early if a previous error has already been recorded.
35        if (!codegen_result->error_msg.empty()) {
36            PRINT_TEST("map_node_to_asm: aborting because error already set: %s",
37                       codegen_result->error_msg.c_str());
38            return;
39        }
40    
41        // Node type sanity check
42        if (node->node_type.empty()) {
43            codegen_result->error_msg = "AST node has no type identifier";
44            PRINT_TEST("map_node_to_asm: %s", codegen_result->error_msg.c_str());
45            return;
46        }
47    
48        // Optional verbose entry diagnostics
49        if (verbose) {
50            std::string entry_msg = "; map_node_to_asm: entering node '" + node->node_type + "'";
51            append_asm_line(codegen_result, entry_msg, verbose);
52        }
53    
54        // Core translation – delegate to the generic emitter.
55        emit_node_asm(node, codegen_result, verbose, temp_regs, label_counter);
56    
57        // Propagate any error produced by emit_node_asm
58        if (!codegen_result->error_msg.empty()) {
59            PRINT_TEST("map_node_to_asm: error after emitting node '%s': %s",
60                       node->node_type.c_str(),
61                       codegen_result->error_msg.c_str());
62            return;
63        }
64    
65        // Optional verbose exit diagnostics
66        if (verbose) {
67            std::string exit_msg = "; map_node_to_asm: exiting node '" + node->node_type + "'";
68            append_asm_line(codegen_result, exit_msg, verbose);
69        }
70    }


