19    bool sema_walk_tu(std::shared_ptr<ASTNode> ast_root,
20                      std::shared_ptr<SemaContext> sema_ctx)
21    {
22        PRINT_TEST("sema_walk_tu start");
23    
24        if (!ast_root || !sema_ctx) {
25            PRINT_TEST("sema_walk_tu received null pointers");
26            return false;
27        }
28    
29        bool success = true;
30        std::vector<std::shared_ptr<Token>> dummy_tokens; // used only for diagnostics
31    
32        // Iterate over each top‑level child of the translation unit.
33        for (std::shared_ptr<ASTNode>& child : ast_root->children) {
34            if (!child) {
35                continue;
36            }
37    
38            PRINT_TEST("Processing top‑level node kind=%d line=%d column=%d",
39                       static_cast<int>(child->kind), child->line, child->column);
40    
41            switch (child->kind) {
42                case EASTNodeKind::VAR_DECL: {
43                    bool decl_success = sema_check_decl(child, sema_ctx);
44                    success = success && decl_success;
45                    PRINT_TEST("VAR_DECL check success=%d", decl_success ? 1 : 0);
46                    break;
47                }
48    
49                case EASTNodeKind::FUNCTION_DECL: {
50                    // Locate the function body (BLOCK) and count any non‑BLOCK children.
51                    std::shared_ptr<ASTNode> body = nullptr;
52                    int non_block_children = 0;
53    
54                    for (std::shared_ptr<ASTNode>& subchild : child->children) {
55                        if (!subchild) {
56                            continue;
57                        }
58                        if (subchild->kind == EASTNodeKind::BLOCK) {
59                            body = subchild;
60                        } else {
61                            ++non_block_children;
62                        }
63                    }
64    
65                    bool minimal = (body != nullptr) && (non_block_children == 0);
66    
67                    if (minimal) {
68                        PRINT_TEST("Detected minimal FUNCTION_DECL at line=%d", child->line);
