18    bool emit_text_section(std::shared_ptr<ASTNode> ast_root,
19                           std::shared_ptr<SCompilerConfig> config,
20                           std::string& asm_out)
21    {
22        PRINT_TEST("emit_text_section: start");
23    
24        if (!config)
25        {
26            PRINT_TEST("emit_text_section: config is null");
27            return false;
28        }
29        if (!ast_root)
30        {
31            PRINT_TEST("emit_text_section: ast_root is null");
32            return false;
33        }
34        if (ast_root->type != ENodeType::PROGRAM)
35        {
36            PRINT_TEST("emit_text_section: root node is not PROGRAM");
37            return false;
38        }
39    
40        asm_out += ".text\n\n";
41        PRINT_TEST("emit_text_section: emitted .text directive");
42    
43        for (auto& child : ast_root->children)
44        {
45            if (!child)
46            {
47                PRINT_TEST("emit_text_section: encountered null child");
48                continue;
49            }
50            if (child->type != ENodeType::FUNCTION_DECL)
51            {
52                continue;
53            }
54    
55            std::string func_name = child->value;
56            if (func_name.empty())
57            {
58                PRINT_TEST("emit_text_section: function node has empty name");
59                continue;
60            }
61    
62            asm_out += ".global ";
63            asm_out += func_name;
64            asm_out += "\n";
65            asm_out += func_name;
66            asm_out += ":\n";
67    
68            if (!emit_func_prologue(child, config, asm_out))
69            {
70                PRINT_TEST("emit_text_section: emit_func_prologue failed for %s", func_name.c_str());
71                return false;
72            }
73    
74            if (!emit_func_body(child, config, asm_out))
75            {
76                PRINT_TEST("emit_text_section: emit_func_body failed for %s", func_name.c_str());
77                return false;
78            }
79    
80            if (!emit_func_epilogue(asm_out, config))
81            {
82                PRINT_TEST("emit_text_section: emit_func_epilogue failed for %s", func_name.c_str());
83                return false;
84            }
85    
86            asm_out += "\n";
87        }
88    
89        PRINT_TEST("emit_text_section: finished");
