52            int tmp_idx = ctx->temp_register_policy.back();
53            ctx->temp_register_policy.pop_back();
54    
55            std::string reg = std::string(use_64bit ? "x" : "w") + std::to_string(tmp_idx);
56            ctx->assembly += "    mov " + reg + ", #" + std::to_string(value) + "\n";
