emit_structural_node_asm: Emits ARM64 assembly for structural AST nodes (programs, blocks, control‑flow, returns). Delegates FunctionDef handling to emit_function_def_and_body_asm.

25    void emit_structural_node_asm(std::shared_ptr<ASTNode> node,
26                                  std::shared_ptr<CodeGenResult> codegen_result,
27                                  bool verbose,
28                                  std::vector<bool>& temp_regs,
29                                  unsigned int& label_counter)
30    {
31        // ---- basic validation -------------------------------------------------
32        if (!node || !codegen_result) {
33            PRINT_TEST("emit_structural_node_asm: null argument(s)");
34            return;
35        }
36        if (!codegen_result->error_msg.empty()) {
37            PRINT_TEST("emit_structural_node_asm: prior error: %s",
38                       codegen_result->error_msg.c_str());
39            return;
40        }
41    
42        const std::string& type = node->node_type;
43        PRINT_TEST("emit_structural_node_asm: processing node type '%s'", type.c_str());
44    
45        // ---- Program ---------------------------------------------------------
46        if (type == "Program") {
47            for (auto& child : node->children) {
48                traverse_ast_post(child, codegen_result, verbose, temp_regs, label_counter);
49                if (!codegen_result->error_msg.empty())
50                    return;
51            }
52            return;
53        }
54    
55        // ---- Function definition ---------------------------------------------
56        if (type == "FunctionDef") {
57            // Delegate full function handling to the helper.
58            emit_function_def_and_body_asm(node,
59                                           codegen_result,
60                                           verbose,
61                                           temp_regs,
62                                           label_counter);
63            return;
64        }
65    
66        // ---- Parameter declarations (handled inside FunctionDef) -------------
67        if (type == "ParamList" || type == "Param") {
68            // Registers were reserved by the helper; no assembly here.
69            return;
70        }
71    
72        // ---- Compound statement (block) --------------------------------------
73        if (type == "CompoundStmt") {
74            for (auto& child : node->children) {
75                traverse_ast_post(child, codegen_result, verbose, temp_regs, label_counter);
76                if (!codegen_result->error_msg.empty())
77                    return;
78            }
79            return;
80        }
81    
82        // ---- If statement ----------------------------------------------------
83        if (type == "IfStmt") {
84            if (node->children.size() < 2) {
85                codegen_result->error_msg =
86                    "emit_structural_node_asm: if statement missing condition or body";
87                PRINT_TEST("%s", codegen_result->error_msg.c_str());
88                return;
89            }
90    
91            // Evaluate condition expression.
92            traverse_ast_post(node->children[0], codegen_result, verbose, temp_regs, label_counter);
93            if (!codegen_result->error_msg.empty())
94                return;
95    
96            std::string cond_reg = node->children[0]->token ? node->children[0]->token->lexeme : "";
97            if (cond_reg.empty()) {
98                codegen_result->error_msg =
99                    "emit_structural_node_asm: condition register missing after evaluation";
100               PRINT_TEST("%s", codegen_result->error_msg.c_str());
101               return;
102           }
103   
104           const std::string end_lbl = gen_unique_label(label_counter);
105           bool has_else = (node->children.size() == 3);
106           std::string else_lbl;
107   
108           if (has_else) {
109               else_lbl = gen_unique_label(label_counter);
110               append_asm_line(codegen_result,
111                               "CBZ " + cond_reg + ", " + else_lbl,
112                               verbose);
113               free_temp_reg(cond_reg, temp_regs);
114           } else {
115               append_asm_line(codegen_result,
116                               "CBZ " + cond_reg + ", " + end_lbl,
117                               verbose);
118               free_temp_reg(cond_reg, temp_regs);
119           }
120   
121           // Then‑branch.
122           traverse_ast_post(node->children[1], codegen_result, verbose, temp_regs, label_counter);
123           if (!codegen_result->error_msg.empty())
124               return;
125   
126           if (has_else) {
127               // Jump over else‑branch.
128               append_asm_line(codegen_result, "B " + end_lbl, verbose);
129               // Else label.
130               append_asm_line(codegen_result, else_lbl + ":", verbose);
131               // Else‑branch.
132               traverse_ast_post(node->children[2], codegen_result, verbose, temp_regs, label_counter);
133               if (!codegen_result->error_msg.empty())
134                   return;
135           }
136   
137           // End label.
138           append_asm_line(codegen_result, end_lbl + ":", verbose);
139           return;
140       }
141   
142       // ---- While statement -------------------------------------------------
143       if (type == "WhileStmt") {
144           if (node->children.size() < 2) {
145               codegen_result->error_msg =
146                   "emit_structural_node_asm: while statement missing condition or body";
147               PRINT_TEST("%s", codegen_result->error_msg.c_str());
148               return;
149           }
150   
151           const std::string start_lbl = gen_unique_label(label_counter);
152           const std::string cond_lbl  = gen_unique_label(label_counter);
153           const std::string end_lbl   = gen_unique_label(label_counter);
154   
155           // Jump to condition first.
156           append_asm_line(codegen_result, "B " + cond_lbl, verbose);
157   
158           // Loop body.
159           append_asm_line(codegen_result, start_lbl + ":", verbose);
160           traverse_ast_post(node->children[1], codegen_result, verbose, temp_regs, label_counter);
161           if (!codegen_result->error_msg.empty())
162               return;
163   
164           // Condition.
165           append_asm_line(codegen_result, cond_lbl + ":", verbose);
166           traverse_ast_post(node->children[0], codegen_result, verbose, temp_regs, label_counter);
167           if (!codegen_result->error_msg.empty())
168               return;
169   
170           std::string cond_reg = node->children[0]->token ? node->children[0]->token->lexeme : "";
171           if (cond_reg.empty()) {
172               codegen_result->error_msg =
173                   "emit_structural_node_asm: while condition register missing";
174               PRINT_TEST("%s", codegen_result->error_msg.c_str());
175               return;
176           }
177   
178           // Exit when condition is false.
179           append_asm_line(codegen_result, "CBZ " + cond_reg + ", " + end_lbl, verbose);
180           free_temp_reg(cond_reg, temp_regs);
181   
182           // Loop back.
183           append_asm_line(codegen_result, "B " + start_lbl, verbose);
184   
185           // End label.
186           append_asm_line(codegen_result, end_lbl + ":", verbose);
187           return;
188       }
189   
190       // ---- Return statement ------------------------------------------------
191       if (type == "ReturnStmt") {
192           if (node->children.empty()) {
193               // Void return.
194               append_asm_line(codegen_result, "ret", verbose);
195               return;
196           }
197   
198           // Evaluate return expression.
199           traverse_ast_post(node->children[0], codegen_result, verbose, temp_regs, label_counter);
200           if (!codegen_result->error_msg.empty())
201               return;
202   
203           std::string expr_reg = node->children[0]->token ? node->children[0]->token->lexeme : "";
204           if (expr_reg.empty()) {
205               codegen_result->error_msg =
206                   "emit_structural_node_asm: return expression register missing";
207               PRINT_TEST("%s", codegen_result->error_msg.c_str());
208               return;
209           }
210   
211           append_asm_line(codegen_result, "MOV x0, " + expr_reg, verbose);
212           free_temp_reg(expr_reg, temp_regs);
213           append_asm_line(codegen_result, "ret", verbose);
214           return;
215       }
216   
217       // ---- Unknown structural node -----------------------------------------
218       codegen_result->error_msg =
219           "emit_structural_node_asm: unknown structural node type '" + type + "'";
220       PRINT_TEST("%s", type.c_str());
221   }


