emit_function_def_and_body_asm: Generates ARM64 assembly for a FunctionDef AST node, emitting directives, reserving argument registers, handling parameters, generating the body, and appending return and size directives.

17    void emit_function_def_and_body_asm(std::shared_ptr<ASTNode> node,
18                                        std::shared_ptr<CodeGenResult> codegen_result,
19                                        bool verbose,
20                                        std::vector<bool>& temp_regs,
21                                        unsigned int& label_counter)
22    {
23        // Basic validation
24        if (!node || !codegen_result) {
25            PRINT_TEST("emit_function_def_and_body_asm: null argument(s)");
26            return;
27        }
28    
29        if (node->node_type != "FunctionDef") {
30            codegen_result->error_msg = "emit_function_def_and_body_asm: node_type not FunctionDef";
31            PRINT_TEST("%s", codegen_result->error_msg.c_str());
32            return;
33        }
34    
35        if (!node->token) {
36            codegen_result->error_msg = "emit_function_def_and_body_asm: node missing token";
37            PRINT_TEST("%s", codegen_result->error_msg.c_str());
38            return;
39        }
40    
41        const std::string& function_name = node->token->lexeme;
42        if (function_name.empty()) {
43            codegen_result->error_msg = "emit_function_def_and_body_asm: function name is empty";
44            PRINT_TEST("%s", codegen_result->error_msg.c_str());
45            return;
46        }
47    
48        if (!codegen_result->error_msg.empty()) {
49            PRINT_TEST("emit_function_def_and_body_asm: prior error: %s",
50                       codegen_result->error_msg.c_str());
51            return;
52        }
53    
54        PRINT_TEST("emit_function_def_and_body_asm: processing function '%s'", function_name.c_str());
55    
56        // Emit function entry directives
57        append_asm_line(codegen_result, ".text", verbose);
58        append_asm_line(codegen_result, ".global " + function_name, verbose);
59        append_asm_line(codegen_result, ".p2align 2", verbose);
60        append_asm_line(codegen_result, ".type " + function_name + ", %function", verbose);
61        append_asm_line(codegen_result, function_name + ":", verbose);
62    
63        // Reserve first eight argument registers (x0-x7)
64        if (temp_regs.size() < 8) {
65            temp_regs.resize(8, false);
66        }
67        for (std::size_t i = 0; i < 8; ++i) {
68            temp_regs[i] = true;
69        }
70    
71        // Handle optional ParamList
72        std::size_t body_index = 1; // default when ParamList is present
73        if (!node->children.empty()) {
74            std::shared_ptr<ASTNode> first_child = node->children[0];
75            if (first_child && first_child->node_type == "ParamList") {
76                for (std::size_t i = 0; i < first_child->children.size(); ++i) {
77                    if (temp_regs.size() <= i) {
78                        temp_regs.resize(i + 1, false);
79                    }
80                    temp_regs[i] = true; // register x<i> used for a parameter
81                }
82            } else {
83                body_index = 0; // no ParamList, body is first child
84            }
85        }
86    
87        // Generate function body
88        if (node->children.size() > body_index && node->children[body_index]) {
89            traverse_ast_post(node->children[body_index],
90                              codegen_result, verbose, temp_regs, label_counter);
91            if (!codegen_result->error_msg.empty()) {
92                return;
93            }
94        }
95    
96        // Release argument registers
97        for (std::size_t i = 0; i < 8; ++i) {
98            std::string reg_name = "x" + std::to_string(i);
99            free_temp_reg(reg_name, temp_regs);
100       }
101   
102       // Emit return and size directive
103       append_asm_line(codegen_result, "ret", verbose);
104       append_asm_line(codegen_result,
105                       ".size " + function_name + ", .-" + function_name,
106                       verbose);
107   }


