35        // ------------------------------------------------------------
36        PRINT_TEST("emit_expr_eval: start (line %d, type %d)",
37                   expr_node ? expr_node->line : -1,
38                   expr_node ? static_cast<int>(expr_node->type) : -1);
39    
40        // ------------------------------------------------------------
41        // Basic validation
42        // ------------------------------------------------------------
43        if (!expr_node) {
44            if (config) {
45                std::shared_ptr<ErrorInfo> err = std::make_shared<ErrorInfo>();
46                err->line    = -1;
47                err->message = "emit_expr_eval: null expression node";
48                config->errors.push_back(err);
49                PRINT_TEST("%s", err->message.c_str());
50            }
51            return false;
52        }
53        if (!config) {
54            PRINT_TEST("emit_expr_eval: null compiler config");
55            return false;
56        }
57    
58        bool ok = true;
59    
60        // ------------------------------------------------------------
61        // Dispatch based on node type
62        // ------------------------------------------------------------
63        switch (expr_node->type) {
64    
65            // ----------------------------------------------------------------
66            // Primary expressions: literals and identifiers
67            // ----------------------------------------------------------------
68            case ENodeType::LITERAL:
69            case ENodeType::IDENTIFIER: {
70                ok = emit_prim(expr_node, false, config, asm_out);
71            } break;
72    
73            // ----------------------------------------------------------------
74            // Unary operators (prefix ++/--, address‑of, deref, logical/bitwise)
75            // ----------------------------------------------------------------
76            case ENodeType::UNARY_OP: {
77                ok = emit_unary(expr_node, false, config, asm_out);
78            } break;
79    
80            // ----------------------------------------------------------------
81            // Increment / decrement operators that have dedicated node types
82            // (postfix/prefix ++/--)
83            // ----------------------------------------------------------------
84            case ENodeType::POSTFIX_INC:
85            case ENodeType::PREFIX_INC:
86            case ENodeType::POSTFIX_DEC:
87            case ENodeType::PREFIX_DEC: {
88                PRINT_TEST("emit_expr_eval: handling inc/dec node type %d at line %d",
89                           static_cast<int>(expr_node->type), expr_node->line);
90                ok = emit_unary_operator_core(expr_node, label_counter, config, asm_out);
91            } break;
92    
93            // ----------------------------------------------------------------
94            // Binary operators (arithmetic, relational, logical, assignment, …)
95            // ----------------------------------------------------------------
96            case ENodeType::BINARY_OP: {
97                ok = emit_expr_eval_binary_op(expr_node, config, label_counter, asm_out);
98            } break;
99    
100           // ----------------------------------------------------------------
101           // Array subscript – compute address then load the element
102           // ----------------------------------------------------------------
103           case ENodeType::ARRAY_SUBSCRIPT: {
104               if (!get_lval_address(expr_node, config, label_counter, asm_out)) {
105                   PRINT_TEST("emit_expr_eval: get_lval_address failed for ARRAY_SUBSCRIPT at line %d",
106                              expr_node->line);
107                   ok = false;
108                   break;
109               }
110   
111               std::size_t elem_sz = normalized_type_size(expr_node->type_spec, config);
112               if (elem_sz == 0) {
113                   // Fallback to a generic word size.
114                   elem_sz = 8;
115               }
116   
117               if (elem_sz == 1) {
118                   asm_out += "    ldrb w0, [x1]\n";
119               } else if (elem_sz == 2) {
120                   asm_out += "    ldrh w0, [x1]\n";
121               } else if (elem_sz == 4) {
122                   asm_out += "    ldr w0, [x1]\n";
123               } else {
124                   asm_out += "    ldr x0, [x1]\n";
125               }
126           } break;
127   
128           // ----------------------------------------------------------------
129           // Generic expression node – may hold a function call or a nested expr
130           // ----------------------------------------------------------------
131           case ENodeType::EXPRESSION: {
132               if (!expr_node->children.empty()) {
133                   std::shared_ptr<ASTNode> child = expr_node->children[0];
134                   // Heuristic: an identifier with children denotes a call.
135                   if (child && child->type == ENodeType::IDENTIFIER && !child->children.empty()) {
136                       ok = emit_call(expr_node, config, label_counter, asm_out);
137                   } else {
138                       ok = emit_expr_eval(child, config, label_counter, asm_out);
139                   }
140               } else {
141                   ok = false;
142                   PRINT_TEST("emit_expr_eval: empty EXPRESSION node at line %d", expr_node->line);
143               }
144           } break;
145   
146           // ----------------------------------------------------------------
147           // Fallback – treat unknown nodes with children as unary (e.g., casts)
148           // ----------------------------------------------------------------
149           default: {
150               if (!expr_node->children.empty()) {
151                   ok = emit_unary(expr_node, false, config, asm_out);
152                   if (!ok) {
153                       PRINT_TEST(
154                           "emit_expr_eval: fallback emit_unary failed for node type %d at line %d",
155                           static_cast<int>(expr_node->type), expr_node->line);
156                   }
157               } else {
158                   ok = false;
159                   PRINT_TEST(
160                       "emit_expr_eval: unsupported node type %d at line %d",
161                       static_cast<int>(expr_node->type), expr_node->line);
162               }
163           } break;
164       }
165   
166       // ------------------------------------------------------------
167       // Error reporting if something went wrong
168       // ------------------------------------------------------------
169       if (!ok && config) {
170           std::shared_ptr<ErrorInfo> err = std::make_shared<ErrorInfo>();
171           err->line    = expr_node->line;
172           err->message = "emit_expr_eval: failed to emit code for node type " +
173                          std::to_string(static_cast<int>(expr_node->type));
174           config->errors.push_back(err);
175           PRINT_TEST("%s", err->message.c_str());
176       }
177   
178       // ------------------------------------------------------------
179       // Debug exit
180       // ------------------------------------------------------------
181       PRINT_TEST("emit_expr_eval: finished %s at line %d",
182                  ok ? "success" : "failure", expr_node->line);
183       return ok;
184   }


